import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { getEachActivities } from "../../features/Activity/ActivitySlice";
import { useParams } from "react-router-dom";

const ActivityDetail = () => {
  const { id } = useParams(); // Get the ID from URL params
  const dispatch = useDispatch();
  const [loading, setLoading] = useState(true);

  // Fetch activities based on the ID parameter
  useEffect(() => {
    dispatch(getEachActivities(id));
    setLoading(false); // Set loading state to false after dispatching
  }, [dispatch, id]);

  const activityLogs = useSelector((state) => state.activity.Eachactivities);

  // Render nested object (details) recursively
  const renderNestedObject = (data) => {
    if (!data || typeof data !== "object") return <span>{String(data)}</span>;

    return (
      <div className="ml-6 border-l-2 border-gray-200 pl-4">
        {Object.entries(data).map(([key, value]) => (
          <div key={key} className="mb-2">
            {/* Check if it's an image URL */}
            {key === "secure_url" && typeof value === "string" ? (
              <div className="flex flex-col items-start">
                <strong className="block mb-1">{key}:</strong>
                <img
                  src={value}
                  alt="Product"
                  className="w-40 h-40 object-cover rounded-lg shadow-md"
                />
              </div>
            ) : typeof value === "object" && value !== null ? (
              // Recursive call for nested objects
              <div>
                <strong>{key}:</strong>
                {renderNestedObject(value)} 
              </div>
            ) : (
              <div>
                <strong>{key}:</strong> {value !== undefined ? String(value) : "N/A"}
              </div>
            )}
          </div>
        ))}
      </div>
    );
  };

  if (loading) return <div className="text-center text-xl">Loading...</div>;
  if (!activityLogs || activityLogs.length === 0)
    return (
      <div className="text-center text-lg text-gray-600">
        No activity found.
      </div>
    );

  return (
    <div className="container mx-auto p-6">
      <h2 className="text-3xl font-bold text-center mb-6">Activity Log</h2>
      <div className="bg-gray-50 shadow rounded-lg p-6">
        <ul className="space-y-6">
          {activityLogs.map((log) => (
            <li key={log._id} className="bg-white shadow rounded-lg p-4">
              <div className="flex justify-between items-center">
                <div>
                  <h3 className="text-xl font-semibold text-gray-800">
                    {log.action}
                  </h3>
                  <p className="text-gray-500 text-sm">
                    {new Date(log.timestamp).toLocaleString()}
                  </p>
                </div>
              </div>
              <div className="mt-4 border-t border-gray-200 pt-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <p className="text-gray-700">
                      <strong>Resource:</strong> {log.resource}
                    </p>
                    <p className="text-gray-700">
                      <strong>Role:</strong> {log.role}
                    </p>
                    <p className="text-gray-700">
                      <strong>User:</strong> {log.user}
                    </p>
                    <p className="text-gray-700">
                      <strong>Timestamp:</strong>{" "}
                      {new Date(log.timestamp).toLocaleString()}
                    </p>
                  </div>
                  <div>
                    <h4 className="text-gray-800 font-semibold mb-2">
                      Additional Details:
                    </h4>
                    {renderNestedObject(log.details)} {/* Render all details */}
                  </div>
                </div>
              </div>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default ActivityDetail;
